The following code generates a 3D house using Three.js. It includes a roof, walls, a door, and a window, all constructed with geometric primitives.

### How to Run
1.  Save the code below as an `.html` file (e.g., `house.html`).
2.  Open the file in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House - Three.js</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. Scene Setup ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // --- 2. Lighting ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 3. Environment ---
        // Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // --- 4. House Construction ---
        const houseGroup = new THREE.Group();

        // Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xf5f5dc }); // Beige
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8b4513 }); // Brown
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x3e2723 }); // Dark Wood
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });

        // Base Dimensions
        const width = 6;
        const depth = 6;
        const height = 4;

        // Walls
        const wallGeo = new THREE.BoxGeometry(width, height, depth);
        const wall = new THREE.Mesh(wallGeo, wallMat);
        wall.position.y = height / 2;
        wall.castShadow = true;
        wall.receiveShadow = true;
        houseGroup.add(wall);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(width, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = height + 1.5;
        roof.rotation.y = Math.PI / 4; // Align square base with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.25, depth / 2 + 0.1);
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);
        const windowMesh = new THREE.Mesh(winGeo, windowMat);
        windowMesh.position.set(0, 2.5, -depth / 2 - 0.1);
        houseGroup.add(windowMesh);

        // Chimney
        const chimGeo = new THREE.BoxGeometry(1, 2, 1);
        const chimney = new THREE.Mesh(chimGeo, wallMat);
        chimney.position.set(2, height + 2, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // --- 5. Controls & Animation ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);

        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        // Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        animate();
    </script>
</body>
</html>
```

### Key Features of this Code:
*   **Three.js Module:** Uses the modern ES module import system via a CDN, so no installation is required.
*   **Lighting:** Includes ambient light for base visibility and a directional light to create shadows.
*   **Geometry:**
    *   **Walls:** A standard BoxGeometry.
    *   **Roof:** A ConeGeometry rotated by 45 degrees to create a pyramid shape.
    *   **Details:** Includes a door, a window (with transparency), and a chimney.
*   **Interactivity:** Uses `OrbitControls` allowing you to click and drag to rotate around the house and scroll to zoom in/out.
*   **Shadows:** Enabled for the walls and roof to give the scene depth.
